/* ──────────────────────────────────────────────
   BTCalendar — organism stylesheet
   Shared with React. No hex fallbacks anywhere.
   ────────────────────────────────────────────── */

/* Container */
.bt-calendar {
  display: inline-flex;
  flex-direction: column;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
  user-select: none;
  box-shadow: 0px 10px 7.5px rgba(0, 0, 0, 0.10), 0px 4px 3px rgba(0, 0, 0, 0.05);
}

/* With presets: row layout */
.bt-calendar--has-presets {
  flex-direction: row;
}

.bt-calendar__preset-panel {
  width: 160px;
  border-inline-end: 1px solid var(--border-primary);
  padding: var(--space-sm) 0;
  flex-shrink: 0;
}

/* Body (right side of preset panel, or full width without presets) */
.bt-calendar__body {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  padding: var(--space-lg);
  gap: var(--space-lg);
}

/* Dual month (range) — side-by-side months */
.bt-calendar__months {
  display: flex;
  flex-direction: row;
  gap: var(--space-lg);
}

.bt-calendar__month {
  padding: 0;
}

.bt-calendar__month-subtitle {
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-secondary);
  padding: var(--space-xs);
  line-height: var(--typography-line-height-xs);
  margin-bottom: var(--space-xs);
}

/* ── Header ─────────────────────────────────── */
.bt-calendar__header {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  margin-bottom: var(--space-sm);
}

/* Nav prev/next buttons */
.bt-calendar__nav-btn {
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  border: none;
  background: none;
  cursor: pointer;
  color: var(--color-brand-primary);
  border-radius: var(--radius-xs);
  flex-shrink: 0;
  transition: background 0.1s;
}

.bt-calendar__nav-btn:hover:not(:disabled) {
  background: var(--bg-subtle);
}

.bt-calendar__nav-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.bt-calendar__header-labels {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  flex: 1;
}

/* Pill wrapper — needed for dropdown anchor reference */
.bt-calendar__pill-wrapper {
  position: relative;
}

/* Month / year pill buttons */
.bt-calendar__header-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  width: 106px;
  padding: var(--space-xs) var(--space-sm);
  border: none;
  background: none;
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--color-brand-primary);
  font-family: var(--typography-font-family-sans);
  border-radius: var(--radius-xs);
  white-space: nowrap;
}

.bt-calendar__header-pill:hover {
  background: var(--bg-subtle);
}

.bt-calendar__header-arrow {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  transition: transform 0.15s ease;
}

.bt-calendar__header-arrow--open {
  transform: rotate(180deg);
}

/* ── Weekday row ─────────────────────────────── */
.bt-calendar__weekdays {
  display: grid;
  grid-template-columns: repeat(7, 40px);
  margin-bottom: var(--space-xs);
}

.bt-calendar__weekday {
  text-align: center;
  font-size: var(--typography-font-size-xs);
  color: var(--text-secondary);
  padding: var(--space-xs) 0;
  width: 40px;
}

/* ── Day grid ────────────────────────────────── */
.bt-calendar__days {
  display: grid;
  grid-template-columns: repeat(7, 40px);
  gap: 0;
  row-gap: var(--space-sm);
}

/* ── Day cell ────────────────────────────────── */
.bt-calendar__day {
  position: relative;
  width: 40px;
  height: 40px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  transition: background 0.1s;
  font-family: var(--typography-font-family-sans);
  padding: 0;
}

.bt-calendar__day:hover:not(.bt-calendar__day--disabled):not(.bt-calendar__day--selected):not(.bt-calendar__day--range-start):not(.bt-calendar__day--range-end):not(.bt-calendar__day--range-start-only):not(.bt-calendar__day--range-start-hover):not(.bt-calendar__day--range-end-hover):not(.bt-calendar__day--in-range):not(.bt-calendar__day--in-range-hover) {
  background: var(--bg-subtle);
}

/* ── Day states ──────────────────────────────── */
.bt-calendar__day--outside {
  color: var(--text-tertiary);
}

.bt-calendar__day--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
}

.bt-calendar__day--today {
  outline: 1.5px solid var(--color-brand-primary);
  outline-offset: -1.5px;
  border-radius: var(--radius-md);
}

.bt-calendar__day--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md);
}

.bt-calendar__day--selected:hover {
  background: var(--color-brand-primary-bold);
}

.bt-calendar__day--range-start {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md) 0 0 var(--radius-md);
}

.bt-calendar__day--range-end {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}

.bt-calendar__day--in-range {
  background: var(--color-brand-primary-subtle);
  color: var(--text-primary);
  border-radius: 0;
}

/* When start and end are the same day */
.bt-calendar__day--range-start.bt-calendar__day--range-end {
  border-radius: var(--radius-md);
}

/* Start selected but no end yet — fully rounded like a single selected day */
.bt-calendar__day--range-start-only {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md);
}

/* Hover preview endpoints — brand primary at reduced opacity (pre-selected state) */
.bt-calendar__day--range-start-hover {
  background: color-mix(in srgb, var(--color-brand-primary-bold) 55%, transparent);
  color: var(--text-inverse);
  border-radius: var(--radius-md) 0 0 var(--radius-md);
}

.bt-calendar__day--range-end-hover {
  background: color-mix(in srgb, var(--color-brand-primary-bold) 55%, transparent);
  color: var(--text-inverse);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}

/* Hover preview fill — lighter than confirmed in-range */
.bt-calendar__day--in-range-hover {
  background: var(--bg-subtle);
  color: var(--text-primary);
  border-radius: 0;
}

/* ── Event dot ───────────────────────────────── */
.bt-calendar__day-dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: var(--color-brand-secondary);
  margin-top: 2px;
  display: block;
  flex-shrink: 0;
}

/* ── Month view (3×4 grid) ───────────────────── */
.bt-calendar__month-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-xs);
  padding: 0 var(--space-sm) var(--space-sm);
}

.bt-calendar__month-item {
  padding: var(--space-sm);
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  text-align: center;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__month-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__month-item--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

.bt-calendar__month-item--current {
  outline: 1.5px solid var(--color-brand-primary);
  outline-offset: -1.5px;
}

/* ── Year view ───────────────────────────────── */
.bt-calendar__year-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  max-height: 224px;
  overflow-y: auto;
  padding: 0 var(--space-sm) var(--space-sm);
}

.bt-calendar__year-item {
  padding: var(--space-sm) var(--space-lg);
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  text-align: start;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__year-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__year-item--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

/* ── Preset panel items ──────────────────────── */
.bt-calendar__preset-item {
  width: 100%;
  padding: var(--space-sm) var(--space-lg);
  border: none;
  background: none;
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-secondary);
  text-align: start;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__preset-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__preset-item--active {
  color: var(--color-brand-primary-bold);
  background: var(--bg-subtle);
  font-weight: var(--typography-font-weight-semibold);
}

/* ── Preset chips (wrap row below the day grid) ─ */
.bt-calendar__preset-chips {
  contain: inline-size;           /* prevent chips from expanding calendar width */
  margin: 0 -16px;                /* break out of bt-calendar__body 16px padding */
  padding: var(--space-lg) var(--space-sm);
  background: var(--bg-secondary);
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  justify-content: center;
}


/* ── Footer (date display + action buttons) ──── */
.bt-calendar__footer {
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.bt-calendar__footer--range {
  flex-direction: row;
  gap: var(--space-sm);
  align-items: center;
}

.bt-calendar__date-display {
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--color-brand-primary);
  font-family: var(--typography-font-family-sans);
  min-height: 20px;
}

.bt-calendar__footer--range .bt-calendar__date-display {
  flex: 1;
  text-align: start;
}

.bt-calendar__footer-actions {
  display: flex;
  gap: var(--space-sm);
}

.bt-calendar__footer-actions > * {
  flex: 1;
}

.bt-calendar__footer--range .bt-calendar__footer-actions > * {
  flex: none;
}

/**
 * BTCalendar — date picker organism.
 * Figma source: node 2561:1340.
 * Supports single-date and date-range modes with optional preset sidebar,
 * month/year dropdown navigation, event dots, and an Apply/Cancel footer.
 *
 * @example Single date picker
 * ```tsx
 * import { BTCalendar } from '@btech/ui-react';
 * const [date, setDate] = useState<Date | null>(null);
 * <BTCalendar value={date} onValueChange={setDate} />
 * ```
 *
 * @example Range picker with presets
 * ```tsx
 * <BTCalendar
 *   mode="range"
 *   rangeValue={range}
 *   onRangeValueChange={setRange}
 *   presets={myPresets}
 *   showFooter
 *   onApply={handleApply}
 *   onCancel={handleCancel}
 * />
 * ```
 */
import './BTCalendar.css';
import { useState, useMemo, useEffect } from 'react';
import type { BTCalendarProps } from './BTCalendar.types';
import { BTCalendarHeader } from './internal/BTCalendarHeader';
import { BTCalendarGrid } from './internal/BTCalendarGrid';
import { BTCalendarPresetPanel } from './internal/BTCalendarPresetPanel';
import { BTButton } from '../../atoms/Button/BTButton';
import { addMonths, isSameDay, getMonthName } from './internal/calendar.utils';

type PresetChip = { key: string; label: string; date: Date; range: [Date, Date] };

function buildPresetChips(locale: string): PresetChip[] {
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const isId = locale.startsWith('id');

  const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
  const tomorrow = new Date(today); tomorrow.setDate(today.getDate() + 1);

  const dow = today.getDay();
  const daysFromMonday = dow === 0 ? 6 : dow - 1;
  const weekStart = new Date(today); weekStart.setDate(today.getDate() - daysFromMonday);
  const weekEnd = new Date(weekStart); weekEnd.setDate(weekStart.getDate() + 6);
  const lastWeekStart = new Date(weekStart); lastWeekStart.setDate(weekStart.getDate() - 7);
  const lastWeekEnd = new Date(weekStart); lastWeekEnd.setDate(weekStart.getDate() - 1);

  const thisMonthStart = new Date(today.getFullYear(), today.getMonth(), 1);
  const thisMonthEnd = new Date(today.getFullYear(), today.getMonth() + 1, 0);
  const lastMonthStart = new Date(today.getFullYear(), today.getMonth() - 1, 1);
  const lastMonthEnd = new Date(today.getFullYear(), today.getMonth(), 0);

  return [
    { key: 'yesterday',  label: isId ? 'Kemarin'     : 'Yesterday',  date: yesterday,      range: [yesterday,      yesterday]      },
    { key: 'today',      label: isId ? 'Hari ini'    : 'Today',      date: today,          range: [today,          today]          },
    { key: 'tomorrow',   label: isId ? 'Besok'       : 'Tomorrow',   date: tomorrow,       range: [tomorrow,       tomorrow]       },
    { key: 'thisWeek',   label: isId ? 'Minggu ini'  : 'This week',  date: weekStart,      range: [weekStart,      weekEnd]        },
    { key: 'lastWeek',   label: isId ? 'Minggu lalu' : 'Last week',  date: lastWeekStart,  range: [lastWeekStart,  lastWeekEnd]    },
    { key: 'thisMonth',  label: isId ? 'Bulan ini'   : 'This month', date: thisMonthStart, range: [thisMonthStart, thisMonthEnd]   },
    { key: 'lastMonth',  label: isId ? 'Bulan lalu'  : 'Last month', date: lastMonthStart, range: [lastMonthStart, lastMonthEnd]   },
  ];
}

export function BTCalendar({
  mode = 'single',
  value,
  onValueChange,
  rangeValue,
  onRangeValueChange,
  presets,
  minDate,
  maxDate,
  disabledDates,
  eventDates,
  initialMonth,
  locale = 'id-ID',
  showFooter = true,
  showPreset = false,
  onApply,
  onCancel,
}: BTCalendarProps) {
  // ── Display state ───────────────────────────────────────────────────────────

  const initialDisplayDate = useMemo(() => {
    if (initialMonth) return new Date(initialMonth);
    if (value) return new Date(value);
    if (rangeValue?.[0]) return new Date(rangeValue[0]);
    return new Date();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // intentionally only on mount

  const [displayDate, setDisplayDate] = useState<Date>(initialDisplayDate);
  const displayDate2 = useMemo(() => addMonths(displayDate, 1), [displayDate]);

  // ── Built-in preset chips ───────────────────────────────────────────────────

  const presetChips = useMemo<PresetChip[]>(
    () => (showPreset ? buildPresetChips(locale) : []),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [showPreset, locale],
  );

  function isChipActive(chip: PresetChip): boolean {
    if (mode === 'single') {
      return value ? isSameDay(value, chip.date) : false;
    }
    return rangeStart !== null && rangeEnd !== null
      ? isSameDay(rangeStart, chip.range[0]) && isSameDay(rangeEnd, chip.range[1])
      : false;
  }

  function handleChipClick(chip: PresetChip) {
    setActivePresetIndex(-1);
    if (mode === 'single') {
      setDisplayDate(new Date(chip.date));
      onValueChange?.(chip.date);
    } else {
      setRangeStart(chip.range[0]);
      setRangeEnd(chip.range[1]);
      setRangeHover(null);
      setDisplayDate(new Date(chip.range[0]));
      onRangeValueChange?.(chip.range);
    }
  }

  // ── Range selection state ───────────────────────────────────────────────────

  const [rangeStart, setRangeStart] = useState<Date | null>(rangeValue?.[0] ?? null);
  const [rangeEnd, setRangeEnd] = useState<Date | null>(rangeValue?.[1] ?? null);
  const [rangeHover, setRangeHover] = useState<Date | null>(null);

  useEffect(() => {
    setRangeStart(rangeValue?.[0] ?? null);
    setRangeEnd(rangeValue?.[1] ?? null);
  }, [rangeValue]);

  // ── Preset state ────────────────────────────────────────────────────────────

  const [activePresetIndex, setActivePresetIndex] = useState<number>(-1);

  function handlePresetSelect(index: number) {
    setActivePresetIndex(index);
    const preset = presets?.[index];
    if (!preset) return;
    const [start, end] = preset.getValue();
    if (mode === 'range' && start) {
      setRangeStart(start);
      setRangeEnd(end ?? null);
      setDisplayDate(new Date(start));
      onRangeValueChange?.(end ? [start, end] : null);
    } else if (mode === 'single' && start) {
      setDisplayDate(new Date(start));
      onValueChange?.(start);
    }
  }

  // ── Navigation ──────────────────────────────────────────────────────────────

  const canGoPrev = useMemo(() => {
    if (!minDate) return true;
    const prev = addMonths(displayDate, -1);
    return (
      prev.getFullYear() > minDate.getFullYear() ||
      (prev.getFullYear() === minDate.getFullYear() &&
        prev.getMonth() >= minDate.getMonth())
    );
  }, [displayDate, minDate]);

  const canGoNext = useMemo(() => {
    if (!maxDate) return true;
    const next = addMonths(displayDate, mode === 'range' ? 2 : 1);
    return (
      next.getFullYear() < maxDate.getFullYear() ||
      (next.getFullYear() === maxDate.getFullYear() &&
        next.getMonth() <= maxDate.getMonth())
    );
  }, [displayDate, maxDate, mode]);

  function handlePrev() {
    setDisplayDate((d) => addMonths(d, -1));
  }

  function handleNext() {
    setDisplayDate((d) => addMonths(d, 1));
  }

  function handleSelectMonth(date: Date) {
    setDisplayDate(date);
  }

  function handleSelectYear(date: Date) {
    setDisplayDate(date);
  }

  // ── Day selection ───────────────────────────────────────────────────────────

  function handleDaySelect(date: Date) {
    setActivePresetIndex(-1);
    if (mode === 'single') {
      onValueChange?.(date);
      return;
    }
    if (!rangeStart) {
      setRangeStart(date);
      setRangeEnd(null);
    } else if (!rangeEnd) {
      if (isSameDay(date, rangeStart)) {
        setRangeStart(null);
        onRangeValueChange?.(null);
      } else if (date < rangeStart) {
        const newEnd = rangeStart;
        setRangeEnd(newEnd);
        setRangeStart(date);
        onRangeValueChange?.([date, newEnd]);
      } else {
        setRangeEnd(date);
        onRangeValueChange?.([rangeStart, date]);
      }
      setRangeHover(null);
    } else {
      if (isSameDay(date, rangeStart)) {
        setRangeEnd(null);
        setRangeHover(null);
      } else if (isSameDay(date, rangeEnd)) {
        setRangeStart(rangeEnd);
        setRangeEnd(null);
        setRangeHover(null);
      } else if (date >= rangeStart) {
        setRangeEnd(date);
        onRangeValueChange?.([rangeStart, date]);
        setRangeHover(null);
      } else {
        setRangeStart(date);
        onRangeValueChange?.([date, rangeEnd]);
      }
    }
  }

  function handleDayHover(date: Date | null) {
    if (mode === 'range' && rangeStart && !rangeEnd) {
      setRangeHover(date);
    }
  }

  // ── Formatted date display ──────────────────────────────────────────────────

  function formatDate(date: Date): string {
    const day = date.getDate().toString().padStart(2, '0');
    const month = date.toLocaleDateString(locale, { month: 'short' });
    const year = date.getFullYear();
    return `${day} ${month} ${year}`;
  }

  const formattedDateDisplay = useMemo(() => {
    if (mode === 'single') {
      return value ? formatDate(value) : 'DD MMM YYYY';
    }
    const start = rangeStart ? formatDate(rangeStart) : 'DD MMM YYYY';
    const end = rangeEnd ? formatDate(rangeEnd) : 'DD MMM YYYY';
    return `${start} - ${end}`;
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, value, rangeStart, rangeEnd, locale]);

  const cancelLabel = locale.startsWith('id') ? 'Batal' : 'Cancel';
  const applyLabel = locale.startsWith('id') ? 'Terapkan' : 'Apply';

  // ── Footer actions ──────────────────────────────────────────────────────────

  function handleApply() {
    if (mode === 'single') {
      onApply?.(value ?? null);
    } else {
      onApply?.(rangeStart && rangeEnd ? [rangeStart, rangeEnd] : null);
    }
  }

  // ── Render ──────────────────────────────────────────────────────────────────

  return (
    <div
      className={[
        'bt-calendar',
        presets?.length ? 'bt-calendar--has-presets' : '',
      ]
        .filter(Boolean)
        .join(' ')}
      role="application"
      aria-label="Kalender"
    >
      {/* Preset panel (left sidebar) */}
      {!!presets?.length && (
        <BTCalendarPresetPanel
          presets={presets}
          activePresetIndex={activePresetIndex}
          onSelect={handlePresetSelect}
        />
      )}

      {/* Calendar body */}
      <div className="bt-calendar__body">
        {/* Single mode: header inside months wrapper, one month */}
        {mode === 'single' ? (
          <div className="bt-calendar__months">
            <div className="bt-calendar__month">
              <BTCalendarHeader
                displayDate={displayDate}
                locale={locale}
                canGoPrev={canGoPrev}
                canGoNext={canGoNext}
                onPrev={handlePrev}
                onNext={handleNext}
                onSelectMonth={handleSelectMonth}
                onSelectYear={handleSelectYear}
              />
              <BTCalendarGrid
                displayDate={displayDate}
                selectedDate={value ?? null}
                disabledDates={disabledDates}
                eventDates={eventDates}
                minDate={minDate}
                maxDate={maxDate}
                locale={locale}
                onSelect={handleDaySelect}
                onHover={handleDayHover}
              />
            </div>
          </div>
        ) : (
          /* Range mode: single shared header + two month columns with subtitles */
          <>
            <BTCalendarHeader
              displayDate={displayDate}
              locale={locale}
              canGoPrev={canGoPrev}
              canGoNext={canGoNext}
              onPrev={handlePrev}
              onNext={handleNext}
              onSelectMonth={handleSelectMonth}
              onSelectYear={handleSelectYear}
            />

            <div className="bt-calendar__months">
              {/* Left month */}
              <div className="bt-calendar__month">
                <div className="bt-calendar__month-subtitle">
                  {getMonthName(displayDate, locale)}
                </div>
                <BTCalendarGrid
                  displayDate={displayDate}
                  rangeStart={rangeStart}
                  rangeEnd={rangeEnd}
                  rangeHover={rangeHover}
                  disabledDates={disabledDates}
                  eventDates={eventDates}
                  minDate={minDate}
                  maxDate={maxDate}
                  locale={locale}
                  onSelect={handleDaySelect}
                  onHover={handleDayHover}
                />
