        )}

        {/* Footer: date display + actions */}
        {showFooter && (
          <div className={`bt-calendar__footer${mode === 'range' ? ' bt-calendar__footer--range' : ''}`}>
            <div className="bt-calendar__date-display">{formattedDateDisplay}</div>
